import random
import math

def is_prime(n, k=20):
    if n < 2: return False
    if n < 4: return True
    if n % 2 == 0: return False
    d, r = n - 1, 0
    while d % 2 == 0:
        d //= 2
        r += 1
    for _ in range(k):
        a = random.randrange(2, n - 1)
        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            continue
        for _ in range(r - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                break
        else:
            return False
    return True

def generate_prime(bits):
    while True:
        p = random.getrandbits(bits) | (1 << (bits - 1)) | 1
        if is_prime(p):
            return p

def mod_inverse(e, phi):
    g, x, _ = extended_gcd(e, phi)
    if g != 1:
        raise ValueError('No modular inverse')
    return x % phi

def extended_gcd(a, b):
    if a == 0:
        return b, 0, 1
    g, x, y = extended_gcd(b % a, a)
    return g, y - (b // a) * x, x

def generate_keypair(bits=512):
    p = generate_prime(bits // 2)
    q = generate_prime(bits // 2)
    n = p * q
    phi = (p - 1) * (q - 1)
    e = 65537
    d = mod_inverse(e, phi)
    return (e, n), (d, n)

def encrypt(msg, pubkey):
    e, n = pubkey
    if isinstance(msg, str):
        msg = int.from_bytes(msg.encode(), 'big')
    return pow(msg, e, n)

def decrypt(cipher, privkey):
    d, n = privkey
    m = pow(cipher, d, n)
    length = (m.bit_length() + 7) // 8
    return m.to_bytes(length, 'big').decode()

print('RSA Key Pair Generator')
print('='*60)
pubkey, privkey = generate_keypair(512)
print(f'Public key (e): {pubkey[0]}')
print(f'Modulus (n):    {pubkey[1]}')
print(f'Private key:    {str(privkey[0])[:40]}...')

message = 'Hello RSA!'
cipher = encrypt(message, pubkey)
plain = decrypt(cipher, privkey)
print(f'\nMessage:    {message}')
print(f'Encrypted:  {cipher}')
print(f'Decrypted:  {plain}')
print(f'Match: {message == plain}')

